package com.demod.fbsr.task;

import com.demod.dcba.CommandReporting;
import com.demod.factorio.Config;
import com.demod.factorio.FactorioData;
import com.demod.fbsr.FBSR;
import com.demod.fbsr.RenderRequest;
import com.demod.fbsr.RenderResult;
import com.demod.fbsr.bs.BSBlueprint;
import com.demod.fbsr.bs.BSBlueprintString;
import org.json.JSONObject;

import javax.imageio.ImageIO;
import java.io.File;
import java.lang.reflect.Field;
import java.time.Instant;
import java.util.Collections;

public class FBSRExtractMain {

	// Change as you like to get what information you need
	public static void main(String[] args) throws Exception {

		Field config = Config.class.getDeclaredField("config");
		config.setAccessible(true);
		config.set(null, new JSONObject(Collections.singletonMap("factorio", "D:\\Program Files (x86)\\Steam\\steamapps\\common\\Factorio")));

		// Prevent NPE
		FactorioData.getTable();
		FBSR.initialize();

		CommandReporting commandReporting = new CommandReporting("Test author", "Test url", Instant.now());
		BSBlueprint blueprint = new BSBlueprint(BSBlueprintString.decodeRaw(
				""
		).getJSONObject("blueprint"));

		RenderRequest request = new RenderRequest(blueprint, commandReporting);

		RenderResult renderResult = FBSR.renderBlueprint(request);
		System.out.println(renderResult);

		File outputFile = new File("D:\\test.png");
		ImageIO.write(renderResult.image, "png", outputFile);
	}

}
